// ToScVal converts DestChainConfigArgs to an xdr.ScVal for contract calls.
func (s DestChainConfigArgs) ToScVal() (xdr.ScVal, error) {
	return scval.BuildStructScVal(map[string]xdr.ScVal{
		"address_bytes_length":          scval.Uint32ToScVal(s.AddressBytesLength),
		"base_execution_gas_cost":       scval.Uint32ToScVal(s.BaseExecutionGasCost),
		"default_ccvs":                  scval.AddressSliceToScVal(s.DefaultCcvs),
		"default_executor":              scval.AddressToScVal(s.DefaultExecutor),
		"dest_chain_selector":           scval.Uint64ToScVal(s.DestChainSelector),
		"lane_mandated_ccvs":            scval.AddressSliceToScVal(s.LaneMandatedCcvs),
		"message_network_fee_usd_cents": scval.Uint32ToScVal(s.MessageNetworkFeeUsdCents),
		"off_ramp":                      scval.BytesToScVal(s.OffRamp),
		"router":                        scval.AddressToScVal(s.Router),
		"token_network_fee_usd_cents":   scval.Uint32ToScVal(s.TokenNetworkFeeUsdCents),
		"token_receiver_allowed":        scval.BoolToScVal(s.TokenReceiverAllowed),
	})
}

// DestChainConfigArgsFromScVal parses an xdr.ScVal into DestChainConfigArgs.
func DestChainConfigArgsFromScVal(val xdr.ScVal) (*DestChainConfigArgs, error) {
	scMap, ok := val.GetMap()
	if !ok || scMap == nil {
		return nil, fmt.Errorf("not a map type")
	}

	result := &DestChainConfigArgs{}
	for _, entry := range *scMap {
		key, ok := entry.Key.GetSym()
		if !ok {
			continue
		}

		switch string(key) {
		case "address_bytes_length":
			v, ok := entry.Val.GetU32()
			if !ok {
				return nil, fmt.Errorf("address_bytes_length is not u32")
			}
			result.AddressBytesLength = uint32(v)
		case "base_execution_gas_cost":
			v, ok := entry.Val.GetU32()
			if !ok {
				return nil, fmt.Errorf("base_execution_gas_cost is not u32")
			}
			result.BaseExecutionGasCost = uint32(v)
		case "default_ccvs":
			vec, ok := entry.Val.GetVec()
			if !ok || vec == nil {
				return nil, fmt.Errorf("default_ccvs is not a vec")
			}
			result.DefaultCcvs = make([]string, len(*vec))
			for i, item := range *vec {
				v, err := scval.AddressFromScVal(item)
				if err != nil {
					return nil, err
				}
				result.DefaultCcvs[i] = v
			}
		case "default_executor":
			v, err := scval.AddressFromScVal(entry.Val)
			if err != nil {
				return nil, fmt.Errorf("default_executor: %w", err)
			}
			result.DefaultExecutor = v
		case "dest_chain_selector":
			v, err := scval.Uint64FromScVal(entry.Val)
			if err != nil {
				return nil, fmt.Errorf("dest_chain_selector: %w", err)
			}
			result.DestChainSelector = v
		case "lane_mandated_ccvs":
			vec, ok := entry.Val.GetVec()
			if !ok || vec == nil {
				return nil, fmt.Errorf("lane_mandated_ccvs is not a vec")
			}
			result.LaneMandatedCcvs = make([]string, len(*vec))
			for i, item := range *vec {
				v, err := scval.AddressFromScVal(item)
				if err != nil {
					return nil, err
				}
				result.LaneMandatedCcvs[i] = v
			}
		case "message_network_fee_usd_cents":
			v, ok := entry.Val.GetU32()
			if !ok {
				return nil, fmt.Errorf("message_network_fee_usd_cents is not u32")
			}
			result.MessageNetworkFeeUsdCents = uint32(v)
		case "off_ramp":
			v, ok := entry.Val.GetBytes()
			if !ok {
				return nil, fmt.Errorf("off_ramp is not bytes")
			}
			result.OffRamp = []byte(v)
		case "router":
			v, err := scval.AddressFromScVal(entry.Val)
			if err != nil {
				return nil, fmt.Errorf("router: %w", err)
			}
			result.Router = v
		case "token_network_fee_usd_cents":
			v, ok := entry.Val.GetU32()
			if !ok {
				return nil, fmt.Errorf("token_network_fee_usd_cents is not u32")
			}
			result.TokenNetworkFeeUsdCents = uint32(v)
		case "token_receiver_allowed":
			v, ok := entry.Val.GetB()
			if !ok {
				return nil, fmt.Errorf("token_receiver_allowed is not bool")
			}
			result.TokenReceiverAllowed = v
		}
	}

	return result, nil
}

